struct Node {
    int starting;
    int no_of_edges;
};

kernel void BFS_1(
    global struct Node* graph_nodes,
    global int* graph_edges,
    global char* graph_mask,
    global char* updating_graph_mask,
    global char* graph_visited,
    global int* cost,
    int no_of_nodes
) {
    int tid = get_global_id(0);

    if (tid < no_of_nodes && graph_mask[tid] == 1) {
        graph_mask[tid] = 0;

        for (int i = graph_nodes[tid].starting; 
             i < (graph_nodes[tid].no_of_edges + graph_nodes[tid].starting); 
             i++) {
            int id = graph_edges[i];
            if (graph_visited[id] == 0) {
                cost[id] = cost[tid] + 1;
                updating_graph_mask[id] = 1;
            }
        }
    }
}

kernel void BFS_2(
    global char* graph_mask,
    global char* updating_graph_mask,
    global char* graph_visited,
    global char* over,
    int no_of_nodes
) {
    int tid = get_global_id(0);

    if (tid < no_of_nodes && updating_graph_mask[tid] == 1) {
        graph_mask[tid] = 1;
        graph_visited[tid] = 1;
        over[0] = 1;
        updating_graph_mask[tid] = 0;
    }
}
